def range_summary(nums):
    if not nums:
        return ''
    nums = sorted(set(nums))
    result = []
    i, n = 0, len(nums)
    while i < n:
        start = nums[i]
        while i + 1 < n and nums[i+1] == nums[i] + 1:
            i += 1
        if start != nums[i]:
            result.append(f"{start}-{nums[i]}")
        else:
            result.append(str(start))
        i += 1
    return ','.join(result)
